                            Id = 13,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Paralelismo com Tasks\n\n### Task.WhenAll — aguarda TODAS as tasks\n```csharp\n// Sem paralelismo (sequencial — lento)\nvar u1 = await BuscarUsuarioAsync(1); // espera\nvar u2 = await BuscarUsuarioAsync(2); // espera\n\n// Com paralelismo — muito mais rápido!\nvar task1 = BuscarUsuarioAsync(1);\nvar task2 = BuscarUsuarioAsync(2);\nvar (u1, u2) = await (task1, task2); // ambas simultâneas\n\n// Ou com array:\nvar ids = new[] { 1, 2, 3, 4 };\nvar usuarios = await Task.WhenAll(ids.Select(id => BuscarUsuarioAsync(id)));\n```\n\n### Task.WhenAny — aguarda a PRIMEIRA a completar\n```csharp\n// Cache race: quem responder primeiro vence\nvar taskBanco = BuscarNoBancoAsync(id);\nvar taskCache = BuscarNoCacheAsync(id);\n\nvar primeira = await Task.WhenAny(taskBanco, taskCache);\nvar resultado = await primeira; // garante exceções propagadas\n```\n\n### Cuidados\n```csharp\n// Task.WhenAll propaga TODAS as exceções\ntry\n{\n    await Task.WhenAll(task1, task2, task3);\n}\ncatch (Exception ex)\n{\n    // ex contém apenas a primeira — inspecione task1.Exception, etc.\n}\n```",
